send '(set -x ; eval "$(tmux display-message -p "#{session_name}" | tr "-" "\n")" ; while sleep 1 ; do for h in yyy ; do date ; ssh "$h" -N -R 127.0.0.1:"$(( $RANDOM % ( $max + 1 - $min ) + $min ))":127.0.0.1:"$port" -oBatchMode=yes -oStrictHostKeyChecking=no -oServerAliveInterval=15 -oExitOnForwardFailure=yes -oConnectTimeout=8 -oConnectionAttempts=1 ; done ; done)'
